import { Hono, type Context, type Next } from "hono"

// `Env` is generated by `wrangler types` into worker-configuration.d.ts
// (globally available). Re-run that command after editing wrangler.jsonc
// bindings (R2 / D1 / KV, etc.). MODELS is typed manually until the next
// regeneration; the intersection stays harmless afterwards. ADMIN_TOKEN and
// DIARY_PASSWORD are secrets (wrangler secret put / .dev.vars).
type AppEnv = {
  Bindings: Env & { MODELS: R2Bucket; ADMIN_TOKEN?: string; DIARY_PASSWORD?: string }
}

const app = new Hono<AppEnv>()

// Global safety net: never let an uncaught error crash the Worker; return
// a clean JSON error for /api/* and fall back to assets otherwise.
app.onError((err, c) => {
  console.error("worker error:", err)
  if (c.req.path.startsWith("/api/")) {
    return c.json({ ok: false, error: "internal_error" }, 500)
  }
  return c.env.ASSETS.fetch(c.req.raw)
})

// All backend routes live under /api/*.
app.get("/api/health", (c) =>
  c.json({ ok: true, service: "daviddong", time: new Date().toISOString() }),
)

// Example: return basic profile info as JSON.
// app.get("/api/hello", (c) => c.json({ hello: "world" }))

// ---- Chord sheets (Chords.app) ----
// Stored in the CHORD_SHEETS KV namespace under "sheet:<id>". Reads are
// public; writes require the ADMIN_TOKEN secret (sent as a Bearer token).

interface SheetChord {
  name: string
  position: { frets: number[]; fingers: number[]; baseFret: number; barres: number[]; midi: number[] }
}

interface Sheet {
  id: string
  name: string
  chords: SheetChord[]
  updatedAt: string
}

const SHEET_PREFIX = "sheet:"

app.use("/api/sheets/*", async (c, next) => {
  if (c.req.method === "GET") return next()
  const token = c.req.header("Authorization")?.replace(/^Bearer\s+/i, "")
  if (!c.env.ADMIN_TOKEN || token === c.env.ADMIN_TOKEN) return next()
  return c.json({ ok: false, error: "unauthorized" }, 401)
})

// List sheets (newest first). Name/count live in KV metadata so listing
// doesn't need a get per sheet.
app.get("/api/sheets", async (c) => {
  const list = await c.env.CHORD_SHEETS.list<{ name: string; chordCount: number; updatedAt: string }>({
    prefix: SHEET_PREFIX,
  })
  const sheets = list.keys
    .map((k) => ({ id: k.name.slice(SHEET_PREFIX.length), ...k.metadata }))
    .sort((a, b) => (b.updatedAt ?? "").localeCompare(a.updatedAt ?? ""))
  return c.json({ ok: true, sheets })
})

app.get("/api/sheets/:id", async (c) => {
  const sheet = await c.env.CHORD_SHEETS.get<Sheet>(SHEET_PREFIX + c.req.param("id"), "json")
  if (!sheet) return c.json({ ok: false, error: "not_found" }, 404)
  return c.json({ ok: true, sheet })
})

app.put("/api/sheets/:id", async (c) => {
  const id = c.req.param("id")
  if (!/^[a-z0-9-]{1,64}$/.test(id)) return c.json({ ok: false, error: "bad_id" }, 400)

  const body = await c.req.json<Partial<Sheet>>().catch(() => null)
  const name = typeof body?.name === "string" ? body.name.trim().slice(0, 80) : ""
  const chords = Array.isArray(body?.chords) ? body.chords.slice(0, 200) : null
  if (!name || !chords) return c.json({ ok: false, error: "bad_request" }, 400)

  const sheet: Sheet = { id, name, chords, updatedAt: new Date().toISOString() }
  await c.env.CHORD_SHEETS.put(SHEET_PREFIX + id, JSON.stringify(sheet), {
    metadata: { name, chordCount: chords.length, updatedAt: sheet.updatedAt },
  })
  return c.json({ ok: true, sheet })
})

app.delete("/api/sheets/:id", async (c) => {
  await c.env.CHORD_SHEETS.delete(SHEET_PREFIX + c.req.param("id"))
  return c.json({ ok: true })
})

// ---- AI diary (Diary.app) ----
// Daily markdown entries stored in the MODELS R2 bucket under diary/, one
// object per day keyed diary/YYYY-MM-DD.md (uploaded by
// scripts/diary/upload.sh or the PUT route below). Entries are private:
// reads require the DIARY_PASSWORD secret (the Diary.app unlock prompt),
// writes require ADMIN_TOKEN, both sent as a Bearer token. Either secret
// being unset leaves that side open — dev convenience, same trade-off as
// chord sheets.

const DIARY_PREFIX = "diary/"
const DIARY_DATE = /^\d{4}-\d{2}-\d{2}$/

const diaryAuth = async (c: Context<AppEnv>, next: Next) => {
  const token = c.req.header("Authorization")?.replace(/^Bearer\s+/i, "")
  const required = c.req.method === "GET" ? c.env.DIARY_PASSWORD : c.env.ADMIN_TOKEN
  if (!required || token === required) return next()
  return c.json({ ok: false, error: "unauthorized" }, 401)
}

// use("/api/diary/*") does not match the bare list route, hence both paths.
app.use("/api/diary", diaryAuth)
app.use("/api/diary/*", diaryAuth)

// List entry dates, newest first. R2 list returns up to 1000 keys per page —
// almost three years of daily entries — so pagination can wait.
app.get("/api/diary", async (c) => {
  const list = await c.env.MODELS.list({ prefix: DIARY_PREFIX })
  const entries = list.objects
    .filter((o) => /^\d{4}-\d{2}-\d{2}\.md$/.test(o.key.slice(DIARY_PREFIX.length)))
    .map((o) => ({ date: o.key.slice(DIARY_PREFIX.length, -3), size: o.size }))
    .sort((a, b) => b.date.localeCompare(a.date))
  return c.json({ ok: true, entries })
})

app.get("/api/diary/:date", async (c) => {
  const date = c.req.param("date")
  if (!DIARY_DATE.test(date)) return c.json({ ok: false, error: "bad_date" }, 400)
  const obj = await c.env.MODELS.get(`${DIARY_PREFIX}${date}.md`)
  if (!obj) return c.json({ ok: false, error: "not_found" }, 404)
  return c.text(await obj.text(), 200, {
    "Content-Type": "text/markdown; charset=utf-8",
    // Private: responses carry auth; only the browser may cache, briefly.
    "Cache-Control": "private, max-age=300",
  })
})

app.put("/api/diary/:date", async (c) => {
  const date = c.req.param("date")
  if (!DIARY_DATE.test(date)) return c.json({ ok: false, error: "bad_date" }, 400)
  const body = await c.req.text()
  if (!body.trim() || body.length > 512 * 1024) {
    return c.json({ ok: false, error: "bad_body" }, 400)
  }
  await c.env.MODELS.put(`${DIARY_PREFIX}${date}.md`, body, {
    httpMetadata: { contentType: "text/markdown; charset=utf-8" },
  })
  return c.json({ ok: true, date, size: body.length })
})

app.delete("/api/diary/:date", async (c) => {
  const date = c.req.param("date")
  if (!DIARY_DATE.test(date)) return c.json({ ok: false, error: "bad_date" }, 400)
  await c.env.MODELS.delete(`${DIARY_PREFIX}${date}.md`)
  return c.json({ ok: true })
})

// ---- HK city tiles (CausewayBay.app) ----
// ~2GB of photogrammetry GLBs (4096px KTX2/UASTC textures) live in R2 under
// hk-tiles/, deliberately kept
// out of git and the static-asset build. In local dev this route never runs
// (vite serves public/models/hk-tiles/); in production the missing asset
// falls through to the Worker, which streams it from the bucket.

app.get("/models/hk-tiles/:file", async (c) => {
  const file = c.req.param("file")
  if (!/^[\w+.-]+$/.test(file)) return c.notFound()

  // Edge-cache tiles so repeat visitors in a colo skip the R2 read entirely.
  const cache = caches.default
  const cached = await cache.match(c.req.raw)
  if (cached) return cached

  const obj = await c.env.MODELS.get(`hk-tiles/${file}`)
  if (!obj) return c.notFound()

  const res = new Response(obj.body, {
    headers: {
      "Content-Type": file.endsWith(".json") ? "application/json" : "model/gltf-binary",
      // manifest.json is the mutable index; tiles only change on a pipeline
      // re-run, so a day of caching is a fine trade against re-downloads.
      "Cache-Control": file === "manifest.json" ? "public, max-age=300" : "public, max-age=86400",
      ETag: obj.httpEtag,
    },
  })
  c.executionCtx.waitUntil(cache.put(c.req.raw, res.clone()))
  return res
})

// Anything not matched by an /api route falls through to static assets
// (the React SPA). The vite plugin serves ./dist via the ASSETS binding.
app.all("*", (c) => c.env.ASSETS.fetch(c.req.raw))

export default app
